202→func generateSchema[T any]() anthropic.ToolInputSchemaParam {
203→	reflector := jsonschema.Reflector{
204→		AllowAdditionalProperties: false,
205→		DoNotReference:            true,
206→	}
207→	var v T
208→	schema := reflector.Reflect(v)
209→	return anthropic.ToolInputSchemaParam{
210→		Properties: schema.Properties,
211→	}
212→}
213→
214→// toolDef pairs an Anthropic tool definition with a destructive flag for rate limiting.
215→type toolDef struct {
216→	Param       anthropic.ToolParam
217→	Destructive bool
218→}
219→
220→// destructiveTools is the set of tools that modify state.
221→var destructiveTools = map[string]bool{
222→	"add_series":                  true,
223→	"remove_failed":               true,
224→	"update_series_monitoring":    true,
225→	"trigger_series_search":       true,
226→	"delete_series":               true,
227→	"remove_blocklist_item":       true,
228→	"grab_release":                true,
229→	"add_movie":                   true,
230→	"remove_failed_movie":         true,
231→	"update_movie_monitoring":     true,
232→	"delete_movie":                true,
233→	"trigger_movie_search":        true,
234→	"grab_movie_release":          true,
235→	"remove_movie_blocklist_item": true,
236→	"approve_request":             true,
237→	"decline_request":             true,
238→	"delete_request":              true,
239→	"retry_request":               true,
240→	"notebook_write":              true,
241→	"notebook_delete":             true,
242→	"enable_indexer":              true,
243→	"update_indexer_priority":     true,
244→	"delete_indexer":              true,
245→}
246→
247→// IsDestructive reports whether the named tool modifies state.
248→func IsDestructive(name string) bool {
249→	return destructiveTools[name]
250→}
