			if err == nil {
				result = map[string]string{"status": "deleted"}
			}
		case "trigger_movie_search":
			var input triggerMovieSearchInput
			if err := json.Unmarshal(rawInput, &input); err != nil {
				return jsonError("invalid input: " + err.Error()), true
			}
