	client := anthropic.NewClient(option.WithAPIKey(apiKey))
	return &Agent{
		client:    &client,
		sonarr:    sonarrClient,
		radarr:    radarrClient,
		prowlarr:  prowlarrClient,
		overseerr: overseerrClient,
