		var input searchIndexersInput
		if err := json.Unmarshal(rawInput, &input); err != nil {
			return jsonError("invalid input: " + err.Error()), true
		}
		result, err = a.prowlarr.Search(ctx, input.Query)
	case "enable_indexer":
		var input enableIndexerInput
		if err := json.Unmarshal(rawInput, &input); err != nil {
