		a.logger.Warn("tool error", "tool", name, "error", err)
		return jsonError(err.Error()), true
	}

	data, marshalErr := json.Marshal(result)
	if marshalErr != nil {
		return jsonError("failed to marshal result: " + marshalErr.Error()), true
	}
	return string(data), true
}

