 29→		if noteType != notebook.Pinned && noteType != notebook.Reference {
 30→			return jsonError("type must be 'pinned' or 'reference'"), true
 31→		}
 32→		// Check for duplicate titles to avoid creating redundant notes.
 33→		if input.ID == "" {
 34→			existing, searchErr := a.notebook.Search(ctx, input.Title)
