 36→				for _, n := range existing {
 37→					if strings.EqualFold(n.Title, input.Title) {
 38→						data, _ := json.Marshal(map[string]string{
 39→							"warning":     "a note with a similar title already exists",
 40→							"existing_id": n.ID,
 41→							"title":       n.Title,
 42→						})
 43→						return string(data), false
 44→					}
 45→				}
 46→			}
 47→		}
 48→		err = a.notebook.Write(ctx, notebook.Note{
 49→			ID:      input.ID,
 50→			Type:    noteType,
 51→			Title:   input.Title,
 52→			Content: input.Content,
 53→		})
